// 质因数分解
vector<pair<int, int>> factorize(int x) {
    vector<pair<int, int>> factors;
    for (int i = 2; i * i <= x; i++) {
        if (x % i == 0) {
            int cnt = 0;
            while (x % i == 0) {
                x /= i;
                cnt++;
            }
            factors.push_back({i, cnt});
        }
    }
    if (x > 1) factors.push_back({x, 1});
    return factors;
}

// 快速幂取模
long long pow_mod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}
// 模逆元（费马小定理，mod为素数）
long long inv(long long a, long long mod) {
    return pow_mod(a, mod - 2, mod);
}

// 扩展欧几里得算法求ax+by=gcd(a,b)
int extgcd(int a, int b, int &x, int &y) {
    if (b == 0) {
        x = 1; y = 0;
        return a;
    }
    int d = extgcd(b, a % b, y, x);
    y -= a / b * x;
    return d;
}
// 求a在模m下的逆元（a与m互质）
int mod_inv(int a, int m) {
    int x, y;
    extgcd(a, m, x, y);
    return (x % m + m) % m;
}

// 预处理阶乘和逆元用于计算组合数
const int MOD = 1e9+7;
vector<long long> fact, inv_fact;
void precompute(int n) {
    fact.resize(n+1);
    inv_fact.resize(n+1);
    fact[0] = 1;
    for (int i = 1; i <= n; i++) fact[i] = fact[i-1] * i % MOD;
    inv_fact[n] = pow_mod(fact[n], MOD-2, MOD);
    for (int i = n-1; i >= 0; i--) inv_fact[i] = inv_fact[i+1] * (i+1) % MOD;
}
long long C(int n, int k) {
    if (k < 0 || k > n) return 0;
    return fact[n] * inv_fact[k] % MOD * inv_fact[n-k] % MOD;
}

// 容斥原理示例：计算1~n中能被a或b整除的数的个数
int count_divisible(int n, int a, int b) {
    int lcm_ab = lcm(a, b);
    return n/a + n/b - n/lcm_ab;
}
// 一般情况：枚举子集
long long inclusion_exclusion(vector<int> primes, long long n) {
    int k = primes.size();
    long long res = 0;
    for (int mask = 1; mask < (1 << k); mask++) {
        long long prod = 1;
        int bits = 0;
        for (int i = 0; i < k; i++) {
            if (mask >> i & 1) {
                prod *= primes[i];
                bits++;
            }
        }
        if (bits % 2 == 1) res += n / prod;
        else res -= n / prod;
    }
    return res;
}

// 欧拉函数：小于n且与n互质的数的个数
int phi(int n) {
    int result = n;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0) n /= i;
            result -= result / i;
        }
    }
    if (n > 1) result -= result / n;
    return result;
}
// 线性筛求欧拉函数
vector<int> get_phi(int n) {
    vector<int> phi(n+1), primes;
    vector<bool> is_prime(n+1, true);
    phi[1] = 1;
    for (int i = 2; i <= n; i++) {
        if (is_prime[i]) {
            primes.push_back(i);
            phi[i] = i - 1;
        }
        for (int p : primes) {
            if (i * p > n) break;
            is_prime[i * p] = false;
            if (i % p == 0) {
                phi[i * p] = phi[i] * p;
                break;
            } else {
                phi[i * p] = phi[i] * (p - 1);
            }
        }
    }
    return phi;
}

// 快速傅里叶变换(FFT)框架（伪代码）
// 实际使用需实现复数运算或使用NTT模数版本
typedef complex<double> cd;
void fft(vector<cd> &a, bool invert) {
    int n = a.size();
    for (int i = 1, j = 0; i < n; i++) {
        int bit = n >> 1;
        for (; j & bit; bit >>= 1) j ^= bit;
        j ^= bit;
        if (i < j) swap(a[i], a[j]);
    }
    for (int len = 2; len <= n; len <<= 1) {
        double ang = 2 * PI / len * (invert ? -1 : 1);
        cd wlen(cos(ang), sin(ang));
        for (int i = 0; i < n; i += len) {
            cd w(1);
            for (int j = 0; j < len/2; j++) {
                cd u = a[i+j], v = a[i+j+len/2] * w;
                a[i+j] = u + v;
                a[i+j+len/2] = u - v;
                w *= wlen;
            }
        }
    }
    if (invert) for (cd &x : a) x /= n;
}
vector<int> multiply(vector<int> const& a, vector<int> const& b) {
    vector<cd> fa(a.begin(), a.end()), fb(b.begin(), b.end());
    int n = 1;
    while (n < a.size() + b.size()) n <<= 1;
    fa.resize(n); fb.resize(n);
    fft(fa, false); fft(fb, false);
    for (int i = 0; i < n; i++) fa[i] *= fb[i];
    fft(fa, true);
    vector<int> result(n);
    for (int i = 0; i < n; i++) result[i] = round(fa[i].real());
    return result;
}

